HTML<pre><code>&lt;!DOCTYPE html&gt;
&lt;html lang="zh-CN"&gt;
&lt;head&gt;
&lt;meta charset="UTF-8"&gt;
&lt;title&gt;锦盒(JH.COM)-正品低价、品质保障、配送及时、轻松购物！&lt;/title&gt;
&lt;link rel="shortcut icon" href="./images/favicon.ico" type="image/x-icon"&gt;
&lt;link rel="stylesheet" href="./css/reset.css"&gt;
&lt;link rel="stylesheet" href="./css/index.css"&gt;
&lt;/head&gt;
&lt;body&gt;
&lt;div class="topbar"&gt;
&lt;div class="container clearfix"&gt;
&lt;div class="welcome leftfix"&gt;
&lt;span class="hello"&gt;锦盒欢迎你&lt;/span&gt;
&lt;span&gt;请&lt;/span&gt;
&lt;a href="#" class="login"&gt;登录&lt;/a&gt;
&lt;a href="#" class="register"&gt;免费注册&lt;/a&gt;
&lt;/div&gt;
&lt;div class="topbar-nav rightfix"&gt;
&lt;ul class="clearfix"&gt;
&lt;li&gt;&lt;a href="#"&gt;我的订单&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href="#"&gt;我的购物车&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href="#"&gt;我的锦盒&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href="#"&gt;锦盒会员&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href="#"&gt;企业采购&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href="#"&gt;关注锦盒&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href="#"&gt;合作招商&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href="#"&gt;商家后台&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/body&gt;
&lt;/html&gt;
</code></pre> CSS<pre><code>/* 基础设置-版心 */
.container {
width: 1190px;
/* 页面水平居中 */
margin: 0 auto;
}
/* 顶部导航条 start */
.topbar {
height: 30px;
background-color: #ececec;
}
.welcome {
height: 30px;
line-height: 30px;
font-size: 0;
color: #666;
}
.welcome span, .welcome a {
font-size: 12px;
}
.welcome .hello {
margin-right: 28px;
}
.welcome .login {
/* 用padding是因为margin在border外面，对border不生效 */
padding-right: 10px;
border-right: 1px solid #666;
}
.welcome .register {
padding-left: 10px;
}
/* 在div内垂直居中 */
.topbar-nav ul {
height: 30px;
line-height: 30px;
}
.topbar-nav ul&gt;li {
/* display: inline-block; 应改用浮动（左）*/
/* 垂直居中应找父元素ul定义 */
float: left;
}
.topbar-nav ul&gt;li&gt;a {
padding: 0 15px;
border-right: 1px solid #666;
}
.topbar-nav ul&gt;li:first-child a {
padding-left: 0;
}
.topbar-nav ul&gt;li:last-child a{
border-style: none;
padding-right: 0;
}
</code></pre>

